import{_ as t,c as r,o as i,aj as a}from"./chunks/framework.guNMSiFm.js";const u=JSON.parse('{"title":"Triggers","description":"","frontmatter":{},"headers":[],"relativePath":"blockchain/triggers.md","filePath":"blockchain/triggers.md","lastUpdated":1777621302000}'),o={name:"blockchain/triggers.md"};function s(c,e,l,n,d,h){return i(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="triggers" tabindex="-1">Triggers <a class="header-anchor" href="#triggers" aria-label="Permalink to &quot;Triggers&quot;">​</a></h1><p>Triggers bind an event filter to an executable action. When an event matches the trigger&#39;s filter, Iroha evaluates the trigger action as part of block execution.</p><h2 id="structure" tabindex="-1">Structure <a class="header-anchor" href="#structure" aria-label="Permalink to &quot;Structure&quot;">​</a></h2><p>A registered <code>Trigger</code> contains:</p><ul><li><code>id</code>: a <code>TriggerId</code> wrapping a <code>Name</code></li><li><code>action</code>: the executable, authority, filter, repetition policy, retry policy, and metadata</li></ul><p>The action contains:</p><ul><li><code>executable</code>: <code>Instructions</code>, <code>ContractCall</code>, <code>Ivm</code>, or <code>IvmProved</code></li><li><code>repeats</code>: <code>Indefinitely</code> or <code>Exactly(n)</code></li><li><code>authority</code>: the account that invokes the executable</li><li><code>filter</code>: an <code>EventFilterBox</code></li><li><code>retry_policy</code>: optional retry behavior for scheduled time triggers</li><li><code>metadata</code>: arbitrary trigger metadata</li></ul><h2 id="event-filters" tabindex="-1">Event Filters <a class="header-anchor" href="#event-filters" aria-label="Permalink to &quot;Event Filters&quot;">​</a></h2><p>Trigger conditions use the same event-filter model as subscriptions. The top-level event filter can match:</p><ul><li>pipeline events</li><li>data events</li><li>time events</li><li>trigger execution events</li><li>trigger completion events</li></ul><p>Prefer the narrowest filter that matches the workflow. Broad filters are useful for diagnostics, but they increase work during block execution.</p><p>See <a href="/iroha-2-docs/blockchain/filters.html">Filters</a> for the current filter families.</p><h2 id="time-triggers" tabindex="-1">Time Triggers <a class="header-anchor" href="#time-triggers" aria-label="Permalink to &quot;Time Triggers&quot;">​</a></h2><p>Time triggers use a time event filter. When the world state view reaches a matching time condition, Iroha executes the trigger action under the trigger authority. Time triggers are the trigger kind that can use the retry policy described below.</p><h2 id="repetition" tabindex="-1">Repetition <a class="header-anchor" href="#repetition" aria-label="Permalink to &quot;Repetition&quot;">​</a></h2><p><code>Repeats::Indefinitely</code> keeps a trigger active until it is unregistered.</p><p><code>Repeats::Exactly(n)</code> allows the trigger to fire a fixed number of times. When the count is exhausted, register a new trigger if the same behavior is needed again.</p><h2 id="authority-and-permissions" tabindex="-1">Authority and Permissions <a class="header-anchor" href="#authority-and-permissions" aria-label="Permalink to &quot;Authority and Permissions&quot;">​</a></h2><p>The trigger authority is the account used to invoke the executable. Use a dedicated technical account for long-lived triggers so the required permissions are explicit and isolated from an operator&#39;s personal account.</p><p>The authority needs the permissions required by the executable instructions or contract call. The account registering the trigger also needs permission to register triggers under the active runtime validator.</p><h2 id="retry-policy" tabindex="-1">Retry Policy <a class="header-anchor" href="#retry-policy" aria-label="Permalink to &quot;Retry Policy&quot;">​</a></h2><p>Time triggers can opt into a retry policy. A retry policy sets:</p><ul><li><code>max_retries</code>: how many retry attempts are allowed after an initial failed firing</li><li><code>retry_after_ms</code>: how long Iroha waits before a retry becomes eligible</li></ul><p>When the retry budget is exhausted, the trigger is unregistered.</p><h2 id="queries" tabindex="-1">Queries <a class="header-anchor" href="#queries" aria-label="Permalink to &quot;Queries&quot;">​</a></h2><p>Use the current trigger queries to inspect trigger state:</p><ul><li><a href="/iroha-2-docs/reference/queries.html#triggers-contracts-transactions-and-blocks"><code>FindTriggers</code></a></li><li><a href="/iroha-2-docs/reference/queries.html#triggers-contracts-transactions-and-blocks"><code>FindActiveTriggerIds</code></a></li><li><a href="/iroha-2-docs/reference/queries.html#triggers-contracts-transactions-and-blocks"><code>FindTriggerById</code></a></li></ul><p>See also:</p><ul><li><a href="/iroha-2-docs/blockchain/trigger-examples.html">Event trigger example</a></li><li><a href="/iroha-2-docs/blockchain/events.html">Events</a></li><li><a href="/iroha-2-docs/blockchain/instructions.html">Instructions</a></li><li><a href="/iroha-2-docs/blockchain/permissions.html">Permissions</a></li></ul>',29)])])}const p=t(o,[["render",s]]);export{u as __pageData,p as default};
